<template><DomainRulesTab :domain-id="domainId" title="Redirects" summary="Redirect matching paths to a new URL." :fields="fields" :columns="columns" :help-items="helpItems" :list="() => redirectsApi.list(domainId)" :create="(v) => redirectsApi.create(domainId, v)" :update="(id, v) => redirectsApi.update(domainId, id, v)" :remove="(id) => redirectsApi.remove(domainId, id)" /></template>
<script setup lang="ts">import DomainRulesTab from './DomainRulesTab.vue'; import { redirectsApi } from '@/lib/api/redirects'; defineProps<{ domainId: string }>(); const helpItems=[{title:'Source examples',body:'Use /old-page for one URL, /blog/ with Prefix for a section, or /promo/* for simple wildcards.'},{title:'Status code',body:'Use 308 for permanent HTTPS-safe moves, 301 for classic permanent redirects, 302 or 307 for temporary moves.'},{title:'Avoid loops',body:'Do not redirect a path back to the same host and path unless the target clearly changes.'}]; const fields=[{key:'enabled',label:'Enabled',type:'checkbox' as const,default:true,help:'Keep disabled while staging a redirect that could affect live visitors.'},{key:'source_path',label:'Source path',default:'/',placeholder:'/old-page',help:'Enter only the path on this domain, beginning with /.'},{key:'target_url',label:'Target URL',default:'https://example.com/',placeholder:'https://www.example.com/new-page',help:'Use the full destination URL, including https://.'},{key:'status_code',label:'Status code',type:'number' as const,default:308,placeholder:'308',help:'Choose 308 or 301 for permanent redirects; use temporary codes while testing.'},{key:'match_type',label:'Match type',options:['exact_path','prefix','wildcard_simple'],default:'exact_path',help:'Exact is safest. Prefix catches everything below a path. Wildcard supports simple * matching.'},{key:'preserve_query',label:'Preserve query',type:'checkbox' as const,default:true,help:'Keep campaign and tracking query strings on the redirected URL.'},{key:'priority',label:'Priority',type:'number' as const,default:100,placeholder:'100',help:'Lower priority values run first, so put specific redirects before broad redirects.'}]; const columns=[{key:'enabled',label:'Enabled'},{key:'source_path',label:'Source'},{key:'target_url',label:'Target'},{key:'status_code',label:'Status'},{key:'actions',label:'Actions'}];</script>
